function LCityMonsterUnit:LoadFogEffect()
    if(self._effectDp == nil)then
        self._effectDp = require("LApp.component.dp.LxEffectDp"):new()
    end
    self._effectDp:InitDp("fx_ui_miwu",self._effRoot.transform)
    self._effectDp:SetLocalPosition(Vector3(checknumber(self._monsterRef.block[1]),checknumber(self._monsterRef.block[2]),0))
