function LCityMonsterUnit:OnEffectLoaded(dp)
    if(dp)then
        local firstId = CtrlCenter.Role:GetFirstMonsterId()
        local init = CtrlCenter.Role:GetInitMonster()
        if(init)then
            if(self._monsterRefId == firstId)then
                local tween = self:NewTweenSeq(dp:GetDpGo(), function()
                    ShowObject(dp:GetDpGo(),false)
                end)
                tween:Append(dp:GetDpTrans():DOLocalMoveX(dp:GetDpTrans().localPosition.x - 10,5))
                tween:PlayForward()
                self._showFog = false
                if(self._monsterMgr.moveCamera == false)then
                    local first = CtrlCenter.Role:GetFirstMonsterId()
                    local firstCfg = GameTable.CityMonsterRef[first]
                    local cityView = CtrlCenter.City:GetCityView()
                    if(cityView)then
                        cityView:OnGuideMove(checknumber(firstCfg.monsterXY[1]),checknumber(firstCfg.monsterXY[2]),0.5,nil)
                        self._monsterMgr.moveCamera = true
                    end
                end

            end

        else
            if(self._monsterRefId == firstId)then
                ShowObject(dp:GetDpGo(),false)
                self._showFog = false
            else
                ShowObject(dp:GetDpGo(),true)
                self._showFog = true
            end

        end


        --
    end
end
