function LCityMonsterUnit:InitMonster(refId,mgr,loadCallBack,callBackObj)
    self._monsterRefId = refId
    self._monsterMgr = mgr
    self._monsterObj = NewGameObject("Monster_"..refId);


    self._monsterTrans = self._monsterObj.transform
    self._monsterTrans:SetParent(self._monsterMgr._npcTrans)
    self._monsterRef = GameTable.CityMonsterRef[self._monsterRefId]
    self._spineRoot = NewGameObject("SpineRoot")
    self._spineRoot.transform:SetParent(self._monsterTrans)
    self._bgRoot = NewGameObject("BGRoot")
    self._bgRoot.transform:SetParent(self._monsterTrans)
    self._effRoot = NewGameObject("EffRoot")
    self._effRoot.transform:SetParent(self._monsterTrans)
    if(self._monsterRef == nil)then
        return
    end
    local x = self._monsterRef.monsterXY[1] or 0
    local y = self._monsterRef.monsterXY[2] or 0

    local pos = Vector3(checknumber(x),checknumber(y),0)

    self:LoadFogEffect()
    self._monsterTrans.localPosition = pos
    --local boxCollider = self._monsterObj:AddComponent(typeOfBoxCollider)
    --boxCollider.size = Vector3(1,1.3,1)
    --boxCollider.center = Vector3(0,0.55,0)
    self._loadCallBack = loadCallBack
    self._callBackObj = callBackObj
    self:LoadSpine()
    self:LoadMonsterBg()
end
function LCityMonsterUnit:LoadMonsterBg()
    local bg =  NewGameObject("Bg")
    bg.transform:SetParent(self._bgRoot.transform)
    local spriteRenderer = bg.gameObject:AddComponent(typeof(UnityEngine.SpriteRenderer))
    local arr = string.split(self._monsterRef.ModelImg,"|")
    local pos = string.split(arr[2],",")
    local x = checknumber(pos[1])
    local y = checknumber(pos[2])
    bg.transform.localPosition = Vector3(x,y,0)
    self:SetImage(spriteRenderer,arr[1])
    spriteRenderer.sortingOrder = 2;

end
function LCityMonsterUnit:GetPosition()
    if(self._monsterTrans == nil)then
        return Vector3.zero
    end
    return self._monsterTrans.position
end
function LCityMonsterUnit:ShowMonster()
    if(self._loaded == false)then
        self._show = true
        return
    end
    ShowObject(self._monsterObj,true)
end
function LCityMonsterUnit:HideMonster()
    if(self._loaded == false)then
        self._show = false
        return
    end
