function LCityMonsterUnit:ExecuteClick()
    ---2025.10.24黄江让注释掉
    --if(ModuleCenter.Story:IsNewbieRunning())then
    --    return
    --end
    if(self._showFog)then
        ShowSysMsg(I18nText(2223))
        return
    end

    local storyType , dataId = CtrlCenter.Story:CheckTrigger(NewbieTriggerType.CityMonster,self._monsterRefId)
    if storyType > 0 and dataId > 0 then
        CtrlCenter.Story:StartStory(dataId);
        return true
    end
    CtrlCenter.City:GetCityView():SetCameraPos(self._monsterTrans.position)
    ShowPanel(UiNames.CityMonsterMenu,{refId = self._monsterRefId})

end
function LCityMonsterUnit:LoadSpine()
    if(self._spineDp)then
        self._spineDp:Dispose()
    end
    self._spineDp = require("LApp.component.dp.LxSpineDp"):new()
    local arr = string.split(self._monsterRef.ModelId[1],"=")
    local monsterId = checknumber(arr[1])
    local heroRef = GameTable.CharacterEffectRef[monsterId]
    local monsterRes = heroRef.model
    --local scale = checknumber(arr[2])
    self._spineDp:InitDp(monsterRes,self._spineRoot.transform)
    self._spineDp:SetLocalPosition(Vector3.zero)

    --self._spineDp:SetScale(scale)
    local z = self._monsterRef.monsterXY[3] or "1"
    self._spineDp:SetFlipX(checknumber(z) == -1)
    local order = self._monsterRef.order or 10
    self._spineDp:SetRenderOrder(order)
    self._spineDp:SetLoadedCallback(function(model)
        self:SetCollider(model)
        if(self._loadCallBack ~= nil)then
            self._loadCallBack(self._callBackObj,self._monsterRefId)
        end
        self._loaded = true
        if(self._show)then
            self:ShowMonster()
        else
            self:HideMonster()
        end
    end)
    self._spineDp:Load()

end

function LCityMonsterUnit:SetCollider(model)
    local arr = string.split(self._monsterRef.ModelId[1],"=")
    local scale = checknumber(arr[2])

    self._spineRoot.transform.localScale = Vector3(scale,scale,scale)
    local go = FindChild(model._dpTrans,"Collider")
    local collider = go.gameObject:GetComponent(typeOfBoxCollider2D)
    local tempSize = collider.size
    local tempCenter = collider.offset
    local size = Vector2(tempSize.x * scale,tempSize.y * scale)
    local center = Vector2(tempCenter.x * scale,tempCenter.y * scale)
    self._boxCollider = self._monsterObj:AddComponent(typeOfBoxCollider)
    self._boxCollider.size = size
    self._boxCollider.center = center
end
function LCityMonsterUnit:OnUpdate(deltaTime)
    if(ModuleCenter.Story:IsNewbieRunning())then
        if(self._totalTime ~= nil and self._totalTime ~= 0)then
            self._timeTick = self._timeTick + deltaTime

            if(self._fadeTime ~= nil and self._fadeTime ~= 0)then
                if(self._isBirth)then
                    self:SetSpineAlpha(self._timeTick/self._fadeTime)
                else
                    self:SetSpineAlpha((self._fadeTime - self._timeTick)/self._fadeTime)
                end
            end

            if(self._timeTick >= self._totalTime)then
                if(self._storyCallBack ~= nil)then
                    self._storyCallBack();
                    self._totalTime = nil
                end
            end
        else
            if(self._storyCallBack ~= nil)then
                self._storyCallBack();
                self._totalTime = nil
            end
        end
        return
    end
end
function LCityMonsterUnit:SetSpineAlpha(a)
    if(self._spineDp)then
        self._spineDp:SetAlpha(a);
    end

end
function LCityMonsterUnit:GetSpineAlpha()
    if(self._spineDp)then
        return self._spineDp:GetAlpha();
    end

end
function LCityMonsterUnit:DoDieFade(fadeTime,stayTime,callBack)
    self._fadeTime = fadeTime
    self._isBirth = false
    self._totalTime = self._fadeTime + stayTime
    self._storyCallBack = callBack
end
function LCityMonsterUnit:DoDie(stayTime,callBack)
    self._fadeTime = nil
    self._totalTime = stayTime
    self:SetSpineAlpha(0)
    self._storyCallBack = callBack
end

function LCityMonsterUnit:DoBirthFade(fadeTime,stayTime,callBack)
    self._fadeTime = fadeTime
    self._isBirth = true
    self._totalTime = fadeTime + stayTime
    self:PlayAni(SpineAniNameEnum.idle,true)
    self._storyCallBack = callBack
end

function LCityMonsterUnit:DoBirth(stayTime,callBack)
    self._fadeTime = nil
    self._totalTime = stayTime
    self:SetSpineAlpha(1)
    self:PlayAni(SpineAniNameEnum.idle,true)
    self._storyCallBack = callBack
end
function LCityMonsterUnit:PlayAni(name)
    if not self._spineDp or not self._spineDp:IsDpValid() then return end
    if(name == "run")then
        local r = false
        local list = self._spineDp:GetAniNameStrList()
        local count = table.nums(list)
        if(count == 0)then
            r = true
        end
        for i = 1, count do
            if(list[i] == "run")then
                r = true
                break
            end
        end
        if(r == false)then
            name = "move"
        end
    end
    if(self._spineDp)then
        self._spineDp:PlayAni(name)
    end

end
return LCityMonsterUnit